        /**
         */
        @kotlin.jvm.JvmStatic
        private fun _addHeaderAndFooter(binaryStylesheet: com.omnifret.gplayer.importer.BinaryStylesheet, style: com.omnifret.gplayer.model.HeaderFooterStyle, prefix: String, name: String): Unit{
            binaryStylesheet.addValue("""${(prefix).toTemplate()}${(name).toTemplate()}""", style.template!!, com.omnifret.gplayer.importer.DataType.String)
            binaryStylesheet.addValue("""${(prefix).toTemplate()}${(name).toTemplate()}Alignment""", style.textAlign.toDouble(), com.omnifret.gplayer.importer.DataType.Integer)
            if (style.isVisible != null)
            {
                binaryStylesheet.addValue("""${(prefix).toTemplate()}draw${(name).toTemplate()}""", (style.isVisible!! as Boolean), com.omnifret.gplayer.importer.DataType.Boolean)
            }
