internal enum class DataType(override val value: Int): com.omnifret.gplayer.core.IGPlayerEnum
{
    Boolean(0),
    Integer(1),
    Float(2),
    String(3),
    Point(4),
    Size(5),
    Rectangle(6),
    Color(7);
    companion object : com.omnifret.gplayer.core.IGPlayerEnumCompanion<DataType>{
        public override val values = arrayOf(Boolean, Integer, Float, String, Point, Size, Rectangle, Color) 
        public override fun fromValue(v:Double): DataType{
            return when(v.toInt()){
                Boolean.value -> Boolean
                Integer.value -> Integer
                Float.value -> Float
                String.value -> String
                Point.value -> Point
                Size.value -> Size
                Rectangle.value -> Rectangle
                Color.value -> Color
                else -> throw ClassCastException("No enum with value $v found")}
        }
    }
}

